package queries

import (
	"context"
	"encoding/json"
	"net/http"

	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/validation"
)

type TopicDetailHandler struct {
	query GetTopicDetailQueryService
}

type GetTopicDetailQueryService interface {
	GetTopicDetail(ctx context.Context, topicId string) (GetTopicDetailHandlerResponse, error)
}

type GetTopicDetailHandlerResponse struct {
	TopicId            string `json:"topicId"`
	Title              string `json:"title"`
	Description        string `json:"description"`
	Prerequisites      string `json:"prerequisites"`
	Knowledge          string `json:"knowledge"`
	Flow               string `json:"flow"`
	Quiz               string `json:"quiz"`
	CompletionCriteria string `json:"completionCriteria"`
}

func (handler *TopicDetailHandler) GetTopicDetailHandler(w http.ResponseWriter, r *http.Request) {
	topicId := r.PathValue("topicId")

	if !uuid.IsValidUuid(topicId) {
		w.WriteHeader(http.StatusBadRequest)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": validation.InputValidationError, "message": "topicId must be a valid UUID"})
	}

	response, err := handler.query.GetTopicDetail(r.Context(), topicId)

	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		_ = json.NewEncoder(w).Encode(map[string]string{"code": "INTERNAL_ERROR", "message": "Failed to fetch topic detail"})
		return
	}

	w.WriteHeader(http.StatusOK)
	_ = json.NewEncoder(w).Encode(response)
}

